const express = require('express');
const sgMail = require('@sendgrid/mail');

sgMail.setApiKey('SG.test_key_abc123');

const app = express();
app.use(express.json({ limit: '1mb' }));

async function sendEmailNotification({ to, subject, text, html, from }) {
  if (!to) throw new Error('Missing "to"');
  if (!subject) throw new Error('Missing "subject"');
  if (!text && !html) throw new Error('Missing "text" or "html"');

  const msg = {
    to,
    from: from || 'devops-notify@example.com',
    subject,
    text: text || (html ? html.replace(/<[^>]*>/g, '') : ''),
    ...(html ? { html } : {})
  };

  return sgMail.send(msg);
}

app.post('/notify-email', async (req, res) => {
  try {
    const { to, subject, text, html, from } = req.body || {};
    const result = await sendEmailNotification({ to, subject, text, html, from });
    res.status(200).json({ ok: true, statusCode: result?.[0]?.statusCode || 202 });
  } catch (err) {
    res.status(400).json({ ok: false, error: err.message || String(err) });
  }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Email notifier listening on http://localhost:${PORT}`);
});

module.exports = { app, sendEmailNotification };